-- ===== VIVÊNCIA — adapt schema + demo content =====

alter table public.experiences alter column host_id drop not null;
alter table public.experiences add column if not exists featured boolean not null default false;

delete from public.experiences where host_id is null;


-- allow admins to update any profile (verify/reject hosts)
drop policy if exists p_upd_admin on public.profiles;
create policy p_upd_admin on public.profiles for update using (public.is_admin()) with check (public.is_admin());
